/* Problem: 388A - Fox and Box Accumulation */
/* Solver: Gusztav Szmolik */

#include <stdio.h>
#include <stdlib.h>

unsigned short x[100];
unsigned short s[100];

int cmp (const void*, const void*);

int main ()
    {
    unsigned short n;
    unsigned short i;
    unsigned short pc;
    unsigned short bc;
    unsigned short sc;

    if (scanf("%hu",&n) != 1)
        return -1;
    if (n < 1 || n > 100)
        return -1;
    for (i = 0; i < n; i++)
        {
        if (scanf("%hu",&x[i]) != 1)
            return -1;
        if (x[i] > 100)
            return -1;
        s[i] = 0;
        }
    qsort (x,n,sizeof(unsigned short),cmp);
    pc = bc = 0;
    while (bc < n)
        {
        sc = 0;
        for (i = 0; i < n; i++)
            if (!s[i] && x[i] >= sc)
                {
                s[i] = 1;
                sc++;
                bc++;
                }
        pc++;
        }
    printf ("%hu\n",pc);
    return 0;
    }

int cmp (p1,p2)
    const void* p1;
    const void* p2;
    {
    unsigned short x1;
    unsigned short x2;

    x1 = *(unsigned short*)p1;
    x2 = *(unsigned short*)p2;
    if (x1 == x2)
        return 0;
    return (x1 > x2 ? 1 : -1);
    }

