use std::io;

fn solve() -> Vec<String> {
    let mut input = "".split_ascii_whitespace();
    let mut read = || loop {
        if let Some(word) = input.next() {
            break word;
        }
        input = {
            let mut input = "".to_owned();
            io::stdin().read_line(&mut input).unwrap();
            if input.is_empty() {
                panic!("reached EOF");
            }
            Box::leak(input.into_boxed_str()).split_ascii_whitespace()
        };
    };
    macro_rules! read(($ty:ty) => (read().parse::<$ty>().unwrap()));

    let mut rr = vec!["".to_string(); 0];

    let t = 1;
    for _ in 0..t {
        let n = read!(usize);
        let mut a = vec![0; n];
        for i in 0..n {
            a[i] = read!(usize);
        }

        a.sort();
        let mut v = vec![false; n];
        let mut r = 0;
        for i in 0..n {
            if v[i] {
                continue;
            }
            v[i] = true;
            r += 1;
            let mut c = 1;
            for j in (i + 1)..n {
                if !v[j] && a[j] >= c {
                    v[j] = true;
                    c += 1;
                }
            }
        }

        rr.push(format!("{}", r));
    }

    rr
}

